DROP TABLE IF EXISTS `caipiao_memberlog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_memberlog` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `userid` int(11) NOT NULL,
  `username` char(60) NOT NULL,
  `type` char(20) NOT NULL COMMENT 'login logout đăng xuấtwithdrawrút tiền',
  `info` varchar(60) NOT NULL,
  `ip` char(20) NOT NULL,
  `iparea` varchar(60) NOT NULL COMMENT 'ipkhu vực',
  `time` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `userid` (`userid`)
) ENGINE=InnoDB AUTO_INCREMENT=340 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;
/*!40101 SET character_set_client = @saved_cs_client */;

